	ClientSecret: "your-client-secret",
	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate redirectPath to prevent open redirect vulnerabilities
	if err := validateRedirectPath(redirectPath); err != nil {
		return "", err
	}

	// Generate cryptographically secure random state
	state, err := generateSecureState()
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config
	config := *OAuthConfig
	// Keep the original RedirectURL from OAuthConfig, don't use redirectPath directly
	// redirectPath is used as a post-auth redirect parameter, not the OAuth callback URL

	// Generate the authorization URL with state parameter
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   300, // 5 minutes expiration
	})

	return authURL, nil
}

// validateRedirectPath ensures the redirect path is safe and doesn't point to external domains
func validateRedirectPath(path string) error {
	if path == "" {
		return errors.New("redirect path cannot be empty")
	}

	// Check if it's an absolute URL (potential open redirect)
	if strings.HasPrefix(path, "http://") || strings.HasPrefix(path, "https://") {
		return errors.New("redirect path cannot be an absolute URL")
	}

	// Ensure it starts with /
	if !strings.HasPrefix(path, "/") {
		return errors.New("redirect path must start with /")
	}

	// Parse to ensure it's a valid URL path
	parsed, err := url.Parse(path)
	if err != nil {
		return errors.New("invalid redirect path format")
	}

	// Ensure no host is specified
	if parsed.Host != "" {
		return errors.New("redirect path cannot contain a host")
	}

	return nil
}

// generateSecureState creates a cryptographically secure random state string
func generateSecureState() (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

