	RedirectURL:  "https://yourapp.com/callback",
	Scopes:       []string{"openid", "profile", "email"},
	Endpoint: oauth2.Endpoint{
		AuthURL:  "https://provider.com/oauth2/authorize",
		TokenURL: "https://provider.com/oauth2/token",
	},
}

// Allowed redirect paths for post-authentication redirection (whitelist)
var allowedRedirectPaths = map[string]bool{
	"/dashboard": true,
	"/home":      true,
	"/profile":   true,
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate redirectPath against whitelist to prevent open redirect attacks
	if !isValidRedirectPath(redirectPath) {
		return "", errors.New("invalid redirect path")
	}

	// Generate cryptographically secure random state to prevent CSRF attacks
	state, err := generateSecureState()
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config
	config := *OAuthConfig
	// IMPORTANT: Do NOT use user-provided redirectPath as RedirectURL
	// The OAuth RedirectURL must match what's registered with the provider
	// redirectPath is only for post-authentication application redirection

	// Generate the authorization URL with state
	authURL := config.AuthCodeURL(state)

	// Set the state in a secure cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		MaxAge:   300, // 5 minutes expiration
	})

	// Store the validated redirect path in a separate secure cookie
	if redirectPath != "" {
		http.SetCookie(w, &http.Cookie{
			Name:     "oauth_redirect",
			Value:    redirectPath,
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteLaxMode,
			Path:     "/",
			MaxAge:   300,
		})
	}

	return authURL, nil
}

// isValidRedirectPath validates the redirect path against a whitelist
func isValidRedirectPath(path string) bool {
	if path == "" {
		return true // Empty path is acceptable, will use default
	}

	// Ensure path starts with / to prevent protocol-relative URLs
	if !strings.HasPrefix(path, "/") {
		return false
	}

	// Prevent path traversal attacks
	if strings.Contains(path, "..") {
		return false
	}

	// Prevent null bytes and other injection attacks
	if strings.ContainsAny(path, "\x00\n\r") {
		return false
	}

	// Check against whitelist
	return allowedRedirectPaths[path]
}

// generateSecureState generates a cryptographically secure random state string
func generateSecureState() (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

