func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	if redirectPath == "" {
		return "", errors.New("redirectPath cannot be empty")
	}

	// Generate a random state parameter for CSRF protection
	state, err := generateState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Set the session cookie if provided
	if session != nil {
		session.Value = state
		http.SetCookie(w, session)
	}

	// Generate the authorization URL with state parameter
	// The redirectPath is passed as a custom parameter to be used after successful authentication
	authURL := OAuthConfig.AuthCodeURL(state, oauth2.SetAuthURLParam("redirect_path", redirectPath))

	return authURL, nil
}

// generateState creates a random state token for CSRF protection
func generateState() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

func main() {
	http.HandleFunc("/login", func(w http.ResponseWriter, r *http.Request) {
		session := &http.Cookie{
