	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
		Expires:  time.Now().Add(15 * time.Minute),
	})

	return authURL, nil
}

// generateSecureState generates a cryptographically secure random state token
func generateSecureState() (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

// validateRedirectPath validates that the redirect path is safe and doesn't contain external URLs
func validateRedirectPath(redirectPath string) error {
	if redirectPath == "" {
		return errors.New("redirect path cannot be empty")
	}

	// Parse the URL to check if it's valid
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return errors.New("invalid redirect URL format")
	}

	// Check if it's an absolute URL with a different host (potential open redirect)
	if parsedURL.IsAbs() && parsedURL.Host != "" {
