		}
	}

	// Check for dangerous patterns
	if strings.Contains(redirectPath, "//") && !strings.HasPrefix(redirectPath, "https://") && !strings.HasPrefix(redirectPath, "http://") {
		return errors.New("redirect URL contains invalid protocol-relative URL")
	}

	return nil
