var allowedRedirectPaths = map[string]bool{
	"/dashboard": true,
	"/profile":   true,
	"/home":      true,
	"/":          true,
}

// generateSecureState generates a cryptographically secure random state value
func generateSecureState() (string, error) {
	bytes := make([]byte, 16)
	if _, err := rand.Read(bytes); err != nil {
		return "", err
	}
	return hex.EncodeToString(bytes), nil
}

// validateRedirectPath ensures the redirect path is safe and within allowed paths
func validateRedirectPath(redirectPath string) (string, error) {
	// If empty, use default
	if redirectPath == "" {
		return OAuthConfig.RedirectURL, nil
	}

	// Check if it's a relative path (starts with /)
	if !strings.HasPrefix(redirectPath, "/") {
		return "", errors.New("redirect path must be a relative path")
	}

	// Prevent path traversal attacks
	if strings.Contains(redirectPath, "..") {
		return "", errors.New("invalid redirect path")
	}

	// Check against allowed paths
	if allowedRedirectPaths[redirectPath] {
		// Construct full URL with the base redirect URL's host
		baseURL, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
