// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Set the session cookie if provided
	if session != nil {
		http.SetCookie(w, session)
	}

	// Generate a random state parameter for CSRF protection
	state, err := generateState()
	if err != nil {
		return "", fmt.Errorf("failed to generate state: %w", err)
	}

	// Store the redirect path in the state parameter for post-auth redirection
	stateWithRedirect := fmt.Sprintf("%s:%s", state, redirectPath)

	// Generate the authorization URL with state parameter
	authURL := OAuthConfig.AuthCodeURL(stateWithRedirect)

	return authURL, nil
}

// generateState generates a random state parameter for CSRF protection
func generateState() (string, error) {
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

func main() {
	http.HandleFunc("/auth", func(w http.ResponseWriter, r *http.Request) {
		redirectPath := r.URL.Query().Get("redirect")
		if redirectPath == "" {
			redirectPath = "/"
		}

		session := &http.Cookie{
			Name:  "oauth_state",
			Value: "state-value",
			Path:  "/",
		}

		authURL, err := GenerateAuthURL(redirectPath, session, w, r)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}

		http.Redirect(w, r, authURL, http.StatusTemporaryRedirect)
	})

	http.ListenAndServe(":8080", nil)
}

